# audio-listener.js
class AudioListener {
    constructor() {
        this.mediaRecorder = null;
        this.audioChunks = [];
        this.isRecording = false;
    }
    start() {
        navigator.mediaDevices.getUserMedia({ audio: true })
            .then(stream => {
                this.mediaRecorder = new MediaRecorder(stream);
                this.isRecording = true;
                this.mediaRecorder.start();
                console.log('Audio recording started');
            })
            .catch(error => console.error('Erro ao acessar microfone:', error));
    }
    stop() {
        if (this.mediaRecorder && this.isRecording) {
            this.mediaRecorder.stop();
            this.isRecording = false;
            console.log('Audio recording stopped');
        }
    }
}
const audioListener = new AudioListener();

# capture-screen.js
class ScreenCapture {
    constructor() {
        this.canvas = null;
        this.context = null;
        this.isCapturing = false;
    }
    async start() {
        try {
            const stream = await navigator.mediaDevices.getDisplayMedia({ video: { cursor: 'always' } });
            const video = document.createElement('video');
            video.srcObject = stream;
            video.play();
            this.isCapturing = true;
            console.log('Screen capture started');
        } catch (error) {
            console.error('Erro ao capturar tela:', error);
        }
    }
    stop() {
        this.isCapturing = false;
        console.log('Screen capture stopped');
    }
    capture() {
        if (this.canvas) {
            return this.canvas.toDataURL('image/png');
        }
        return null;
    }
}
const screenCapture = new ScreenCapture();

# interaction-handler.js
class InteractionHandler {
    constructor() {
        this.listeners = {};
    }
    on(event, callback) {
        if (!this.listeners[event]) {
            this.listeners[event] = [];
        }
        this.listeners[event].push(callback);
    }
    emit(event, data) {
        if (this.listeners[event]) {
            this.listeners[event].forEach(callback => callback(data));
        }
    }
}
const interactionHandler = new InteractionHandler();
function startVoice() {
    audioListener.start();
    addMessage('Voz iniciada...');
}
function startVision() {
    screenCapture.start();
    addMessage('Visao iniciada...');
}
function startScreen() {
    const screenshot = screenCapture.capture();
    if (screenshot) {
        addMessage('Tela capturada');
    }
}
function sendMessage() {
    const input = document.getElementById('input');
    const message = input.value.trim();
    if (message) {
        addMessage('Voce: ' + message);
        input.value = '';
        interactionHandler.emit('message', message);
    }
}
function addMessage(text) {
    const messagesDiv = document.getElementById('messages');
    const messageEl = document.createElement('div');
    messageEl.className = 'message';
    messageEl.textContent = text;
    messagesDiv.appendChild(messageEl);
    messagesDiv.scrollTop = messagesDiv.scrollHeight;
}
function clearMessages() {
    document.getElementById('messages').innerHTML = '';
}

# sync-engine.js
class SyncEngine {
    constructor(apiUrl = 'http://localhost:5000') {
        this.apiUrl = apiUrl;
        this.syncInterval = 1000;
        this.isConnected = false;
    }
    async sync() {
        try {
            const response = await fetch(this.apiUrl + '/api/health');
            const data = await response.json();
            this.isConnected = data.status === 'ok';
            updateStatus(this.isConnected);
            return this.isConnected;
        } catch (error) {
            console.error('Sync error:', error);
            this.isConnected = false;
            updateStatus(false);
            return false;
        }
    }
    start() {
        setInterval(() => this.sync(), this.syncInterval);
        this.sync();
    }
}
const syncEngine = new SyncEngine();
function updateStatus(connected) {
    const statusEl = document.getElementById('status');
    if (connected) {
        statusEl.textContent = 'Status: Conectado';
        statusEl.style.background = '#e8f5e9';
    } else {
        statusEl.textContent = 'Status: Desconectado';
        statusEl.style.background = '#ffebee';
    }
}
window.addEventListener('load', () => {
    syncEngine.start();
});

